/// Handles biometric authentication using platform APIs with strong requirements.
class BiometricAuthService {
  final LocalAuthentication _localAuth = LocalAuthentication();

  /// Check if biometric hardware is available.
  Future<BiometricAvailability> checkBiometricAvailability() async {
    try {
      final canCheckBiometrics = await _localAuth.canCheckBiometrics;
      final isDeviceSupported = await _localAuth.isDeviceSupported();

      if (!canCheckBiometrics || !isDeviceSupported) {
        return BiometricAvailability(
          isAvailable: false,
          availableBiometrics: [],
          reason: 'Biometric hardware not available or not supported.',
        );
      }

      final availableBiometrics = await _localAuth.getAvailableBiometrics();

      if (availableBiometrics.isEmpty) {
        return BiometricAvailability(
          isAvailable: false,
          availableBiometrics: [],
          reason: 'No biometrics enrolled on this device.',
        );
      }

      return BiometricAvailability(
        isAvailable: true,
        availableBiometrics: availableBiometrics,
      );
    } on PlatformException catch (e) {
      return BiometricAvailability(
        isAvailable: false,
        availableBiometrics: [],
        reason: 'Platform error: ${e.message}',
      );
    }
  }

  /// Authenticate using biometrics with strong authentication requirements.
  /// Uses biometricOnly: false to allow device credential fallback at the OS level,
  /// but the session is only created after successful platform authentication.
  Future<BiometricAuthResult> authenticate({
    required String reason,
    bool biometricOnly = true,
  }) async {
    try {
      final didAuthenticate = await _localAuth.authenticate(
        localizedReason: reason,
        options: AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: biometricOnly,
          useErrorDialogs: true,
          sensitiveTransaction: true,
        ),
      );

      if (didAuthenticate) {
        return BiometricAuthResult(
          success: true,
          method: biometricOnly
              ? AuthMethod.biometric
              : AuthMethod.deviceCredential,
        );
      } else {
        return BiometricAuthResult(
          success: false,
          error: 'Authentication was not successful.',
        );
      }
    } on PlatformException catch (e) {
      String errorMessage;
      switch (e.code) {
        case 'NotAvailable':
          errorMessage = 'Biometric authentication is not available.';
          break;
        case 'NotEnrolled':
          errorMessage = 'No biometrics are enrolled on this device.';
          break;
        case 'LockedOut':
          errorMessage = 'Too many attempts. Biometric is locked out.';
          break;
        case 'PermanentlyLockedOut':
          errorMessage =
              'Biometric is permanently locked. Use device passcode.';
          break;
        default:
          errorMessage = 'Authentication error: ${e.message}';
      }
      return BiometricAuthResult(
        success: false,
        error: errorMessage,
        platformException: e,
      );
    }
  }

  /// Cancel any ongoing authentication.
  Future<void> cancelAuthentication() async {
    await _localAuth.stopAuthentication();
  }
}

class BiometricAvailability {
  final bool isAvailable;
  final List<BiometricType> availableBiometrics;
  final String? reason;

  BiometricAvailability({
    required this.isAvailable,
    required this.availableBiometrics,
    this.reason,
  });

  bool get hasFaceId => availableBiometrics.contains(BiometricType.face);
  bool get hasFingerprint =>
      availableBiometrics.contains(BiometricType.fingerprint);
  bool get hasIris => availableBiometrics.contains(BiometricType.iris);

  String get biometricTypeLabel {
    if (hasFaceId) return 'Face ID';
    if (hasFingerprint) return 'Fingerprint';
    if (hasIris) return 'Iris';
    return 'Biometric';
  }
}

