  BiometricAvailability? _biometricAvailability;

  @override
  void initState() {
    super.initState();
    _loadSettings();
  }

  Future<void> _loadSettings() async {
    final availability = await _biometricService.checkBiometricAvailability();
    final enrolled =
        await SecureSessionManager.isBiometricEnrolled(widget.userId);

    if (mounted) {
      setState(() {
        _biometricAvailability = availability;
        _isBiometricEnrolled = enrolled;
      });
    }
  }

  Future<void> _toggleBiometric(bool enable) async {
    if (enable) {
      // To enable biometric, first re-authenticate with biometric to confirm
      final result = await _biometricService.authenticate(
        reason: 'Verify biometric to enable for future logins',
        biometricOnly: true,
      );

      if (result.success) {
        await SecureSessionManager.enrollBiometric(widget.userId);
        setState(() {
          _isBiometricEnrolled = true;
        });
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Biometric login enabled!'),
              backgroundColor: Colors.green,
            ),
          );
        }
      } else {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text(result.error ?? 'Biometric verification failed.'),
              backgroundColor: Colors.red,
            ),
          );
        }
      }
    } else {
      // To disable, require biometric verification first (prevent unauthorized disabling)
      final result = await _biometricService.authenticate(
        reason: 'Verify your identity to disable biometric login',
        biometricOnly: false,
      );

      if (result.success) {
        await SecureSessionManager.unenrollBiometric(widget.userId);
        setState(() {
          _isBiometricEnrolled = false;
        });
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Biometric login disabled.'),
            ),
          );
        }
      }
    }
  }

  Future<void> _logout() async {
    await SecureSessionManager.destroySession();
    widget.onLogout();
  }

  Future<void> _performSensitiveAction() async {
    // For sensitive actions, always re-verify with biometric or device credential
    final result = await _biometricService.authenticate(
      reason: 'Verify your identity for this sensitive action',
      biometricOnly: false,
    );

    if (result.success && mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Sensitive action authorized and performed!'),
          backgroundColor: Colors.green,
        ),
      );
    } else if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(result.error ?? 'Authorization failed.'),
          backgroundColor: Colors.red,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        actions: [
          IconButton(
            icon: const Icon(Icons.logout),
            onPressed: _logout,
            tooltip: 'Logout',
          ),
        ],
      ),
      body: ListView(
        padding: const EdgeInsets.all(16),
        children: [
          // User info card
          Card(
            child: Padding(
              padding: const EdgeInsets.all(20),
              child: Column(
                children: [
                  CircleAvatar(
                    radius: 40,
                    backgroundColor: theme.colorScheme.primaryContainer,
                    child: Icon(
                      Icons.person,
                      size: 40,
                      color: theme.colorScheme.onPrimaryContainer,
                    ),
                  ),
                  const SizedBox(height: 16),
                  Text(
                    'Welcome, ${widget.userId}!',
                    style: theme.textTheme.headlineSmall?.copyWith(
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    'Authenticated securely',
                    style: TextStyle(color: theme.colorScheme.onSurfaceVariant),
                  ),
                  const SizedBox(height: 8),
                  Chip(
                    avatar: const Icon(Icons.verified_user, size: 18),
                    label: const Text('Session Active'),
                    backgroundColor: Colors.green.withOpacity(0.1),
                    side: const BorderSide(color: Colors.green),
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 16),

          // Security settings
          Card(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Padding(
                  padding: const EdgeInsets.fromLTRB(16, 16, 16, 8),
                  child: Text(
                    'Security Settings',
                    style: theme.textTheme.titleMedium?.copyWith(
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
                if (_biometricAvailability?.isAvailable == true)
                  SwitchListTile(
                    title: Text(
                        '${_biometricAvailability!.biometricTypeLabel} Login'),
                    subtitle: Text(
                      _isBiometricEnrolled
                          ? 'Use ${_biometricAvailability!.biometricTypeLabel.toLowerCase()} to sign in'
                          : 'Enable for faster login',
                    ),
                    secondary: Icon(
                      _biometricAvailability!.hasFaceId
                          ? Icons.face
                          : Icons.fingerprint,
                    ),
                    value: _isBiometricEnrolled,
                    onChanged: _toggleBiometric,
                  )
                else
                  ListTile(
                    leading: const Icon(Icons.fingerprint),
                    title: const Text('Biometric Login'),
                    subtitle: Text(
                      _biometricAvailability?.reason ??
                          'Not available on this device',
                    ),
                    enabled: false,
                  ),
                const Divider(height: 1),
                ListTile(
                  leading: const Icon(Icons.security),
                  title: const Text('Perform Sensitive Action'),
                  subtitle:
                      const Text('Requires re-authentication'),
                  trailing: const Icon(Icons.chevron_right),
                  onTap: _performSensitiveAction,
                ),
              ],
            ),
          ),
          const SizedBox(height: 16),

          // Security info card
          Card(
            color: theme.colorScheme.surfaceContainerHighest,
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      Icon(Icons.shield_outlined,
                          color: theme.colorScheme.primary),
                      const SizedBox(width: 8),
                      Text(
                        'Security Info',
                        style: theme.textTheme.titleSmall?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 12),
                  _buildSecurityInfoRow(
                    'Session storage',
                    'Encrypted (Keychain/Keystore)',
                    Icons.check_circle,
                    Colors.green,
                  ),
                  const SizedBox(height: 8),
                  _buildSecurityInfoRow(
                    'Password storage',
                    'Salted SHA-256 hash',
                    Icons.check_circle,
                    Colors.green,
                  ),
                  const SizedBox(height: 8),
                  _buildSecurityInfoRow(
                    'Biometric binding',
                    'Platform API verified',
                    Icons.check_circle,
                    Colors.green,
                  ),
                  const SizedBox(height: 8),
                  _buildSecurityInfoRow(
                    'Session expiry',
                    '7 days',
                    Icons.timer,
                    Colors.orange,
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 24),

          // Logout button
          OutlinedButton.icon(
            onPressed: _logout,
            icon: const Icon(Icons.logout),
            label: const Text('Sign Out'),
            style: OutlinedButton.styleFrom(
              foregroundColor: theme.colorScheme.error,
              side: BorderSide(color: theme.colorScheme.error),
              padding: const EdgeInsets.symmetric(vertical: 16),
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(12),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSecurityInfoRow(
    String label,
    String value,
    IconData icon,
    Color iconColor,
  ) {
    return Row(
      children: [
        Icon(icon, size: 16, color: iconColor),
        const SizedBox(width: 8),
        Text(
          '$label: ',
          style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13),
        ),
        Expanded(
          child: Text(
            value,
            style: TextStyle(
              fontSize: 13,
              color: Theme.of(context).colorScheme.onSurfaceVariant,
            ),
          ),
        ),
      ],
    );
  }
}